import React from 'react';
import { Card, CardContent, Box, Typography, Stack } from '@mui/material';
import { BarChart } from '@mui/x-charts';
import response from './response.json';

interface WeeklyMinutes {
  day: string;
  minutes: number;
}

interface MeditationData {
  currentStreak: {
    days: number;
    longestStreak: number;
  };
  totalSessions: number;
  weeklyMinutes: WeeklyMinutes[];
}

export default function Widget() {
  const meditationData = response.data as MeditationData;
  const { currentStreak, totalSessions, weeklyMinutes } = meditationData;

  return (
    <Card sx={{ width: 'fit-content', minWidth: 350, maxWidth: 450, bgcolor: '#1F2937', color: '#F8FAFC' }} elevation={2}>
      <CardContent sx={{ p: 2.5 }}>
        <Stack spacing={2}>
          <Box>
            <Typography variant="h6" fontWeight={600} sx={{ mb: 1 }}>
              Meditation Streak
            </Typography>
            <Typography variant="body2" sx={{ color: '#94A3B8' }}>
              Current Streak: {currentStreak.days} days
            </Typography>
            <Typography variant="body2" sx={{ color: '#94A3B8' }}>
              Longest Streak: {currentStreak.longestStreak} days
            </Typography>
            <Typography variant="body2" sx={{ color: '#94A3B8', mt: 1 }}>
              Total Sessions: {totalSessions}
            </Typography>
          </Box>

          <BarChart
            height={120}
            series={[
              {
                data: weeklyMinutes.map(d => d.minutes),
                color: '#3B82F6',
              },
            ]}
            xAxis={[
              {
                data: weeklyMinutes.map(d => d.day),
                scaleType: 'band',
                tickLabelStyle: {
                  fontSize: 11,
                  fill: '#CBD5E1',
                },
              }
            ]}
            margin={{ top: 10, bottom: 30, left: 40, right: 10 }}
            sx={{
              '& .MuiBarElement-root': {
                rx: 4,
              },
            }}
          />
        </Stack>
      </CardContent>
    </Card>
  );
}
